    13→
    14→type slackConfig struct {
    15→	WebhookURL string `json:"webhook_url"`
    16→}
    17→
    18→// SlackSender sends notifications as Slack Block Kit messages via incoming webhook.
    19→type SlackSender struct {
    20→	Client *http.Client
    21→}
    22→
    23→// slackPayload is the Slack incoming webhook payload using Block Kit.
    24→type slackPayload struct {
    25→	Blocks []slackBlock `json:"blocks"`
    26→}
    27→
    28→type slackBlock struct {
    29→	Type     string      `json:"type"`
    30→	Text     *slackText  `json:"text,omitempty"`
    31→	Fields   []slackText `json:"fields,omitempty"`
    32→	Elements []slackText `json:"elements,omitempty"`
    33→}
    34→
    35→type slackText struct {
    36→	Type string `json:"type"`
    37→	Text string `json:"text"`
    38→}
    39→
    40→// riskEmoji returns an emoji indicator for the given risk level.
    41→func riskEmoji(level string) string {
    42→	switch strings.ToUpper(strings.TrimSpace(level)) {
    43→	case "LOW":
    44→		return "🟢"
    45→	case "MEDIUM":
    46→		return "🟡"
    47→	case "HIGH":
    48→		return "🔴"
    49→	case "CRITICAL":
    50→		return "⚫"
    51→	default:
    52→		return "⚪"
    53→	}
    54→}
    55→
    56→// buildSemanticBlocks builds rich Slack Block Kit blocks from a SemanticReport.
    57→func buildSemanticBlocks(title string, report *models.SemanticReport) []slackBlock {
    58→	blocks := []slackBlock{
    59→		{Type: "header", Text: &slackText{Type: "plain_text", Text: title}},
    60→	}
    61→
    62→	// Subject as the lead section
    63→	if report.Subject != "" {
    64→		blocks = append(blocks, slackBlock{
    65→			Type: "section",
    66→			Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*%s*", report.Subject)},
    67→		})
    68→	}
    69→
    70→	// Risk + Urgency + Availability as compact fields
    71→	blocks = append(blocks, slackBlock{
    72→		Type: "section",
    73→		Fields: []slackText{
    74→			{Type: "mrkdwn", Text: fmt.Sprintf("*Risk Level:*\n%s %s", riskEmoji(report.RiskLevel), report.RiskLevel)},
    75→			{Type: "mrkdwn", Text: fmt.Sprintf("*Urgency:*\n%s", report.Urgency)},
    76→			{Type: "mrkdwn", Text: fmt.Sprintf("*Availability:*\n%s", report.Availability)},
    77→		},
    78→	})
    79→
    80→	// Risk reason
    81→	if report.RiskReason != "" {
    82→		blocks = append(blocks,
    83→			slackBlock{Type: "divider"},
    84→			slackBlock{
    85→				Type: "section",
    86→				Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*Risk Assessment*\n%s", report.RiskReason)},
    87→			},
    88→		)
    89→	}
    90→
    91→	// Status checks
    92→	if len(report.StatusChecks) > 0 {
    93→		var items []string
    94→		for _, check := range report.StatusChecks {
    95→			items = append(items, fmt.Sprintf("• %s", check))
    96→		}
    97→		blocks = append(blocks,
    98→			slackBlock{Type: "divider"},
    99→			slackBlock{
   100→				Type: "section",
   101→				Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*Status Checks*\n%s", strings.Join(items, "\n"))},
   102→			},
   103→		)
   104→	}
   105→
   106→	// Changelog summary
   107→	summary := report.ChangelogSummary
   108→	if summary == "" {
   109→		summary = report.Summary
   110→	}
   111→	if summary != "" {
   112→		blocks = append(blocks,
   113→			slackBlock{Type: "divider"},
   114→			slackBlock{
   115→				Type: "section",
   116→				Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*Changelog*\n%s", summary)},
   117→			},
   118→		)
   119→	}
   120→
   121→	// Adoption
   122→	if report.Adoption != "" {
   123→		blocks = append(blocks, slackBlock{
   124→			Type: "section",
   125→			Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*Adoption*\n%s", report.Adoption)},
   126→		})
   127→	}
   128→
   129→	// Download commands as code block
   130→	if len(report.DownloadCommands) > 0 {
   131→		blocks = append(blocks,
   132→			slackBlock{Type: "divider"},
   133→			slackBlock{
   134→				Type: "section",
   135→				Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*Download Commands*\n```%s```", strings.Join(report.DownloadCommands, "\n"))},
   136→			},
   137→		)
   138→	}
   139→
   140→	// Download links
   141→	if len(report.DownloadLinks) > 0 {
   142→		var links []string
   143→		for _, link := range report.DownloadLinks {
   144→			links = append(links, fmt.Sprintf("• <%s>", link))
   145→		}
   146→		blocks = append(blocks, slackBlock{
   147→			Type: "section",
   148→			Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("*Download Links*\n%s", strings.Join(links, "\n"))},
   149→		})
   150→	}
   151→
   152→	// Footer context
   153→	blocks = append(blocks,
   154→		slackBlock{Type: "divider"},
   155→		slackBlock{
   156→			Type: "context",
   157→			Elements: []slackText{
   158→				{Type: "mrkdwn", Text: "📡 _Sent by Changelogue_"},
   159→			},
   160→		},
   161→	)
   162→
   163→	return blocks
   164→}
   165→
   166→func (s *SlackSender) Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error {
   167→	var cfg slackConfig
   168→	if err := json.Unmarshal(ch.Config, &cfg); err != nil {
   169→		return fmt.Errorf("parse slack config: %w", err)
   170→	}
   171→
   172→	// Try to parse body as a SemanticReport for rich formatting.
   173→	var blocks []slackBlock
   174→	var report models.SemanticReport
   175→	if err := json.Unmarshal([]byte(msg.Body), &report); err == nil && report.Subject != "" {
   176→		blocks = buildSemanticBlocks(msg.Title, &report)
   177→	} else {
   178→		// Fallback: simple header + body for non-report messages.
   179→		blocks = []slackBlock{
   180→			{Type: "header", Text: &slackText{Type: "plain_text", Text: msg.Title}},
   181→			{Type: "section", Text: &slackText{Type: "mrkdwn", Text: msg.Body}},
   182→		}
   183→	}
   184→
   185→	payload := slackPayload{Blocks: blocks}
   186→
   187→	body, err := json.Marshal(payload)
   188→	if err != nil {
   189→		return fmt.Errorf("marshal slack payload: %w", err)
   190→	}
   191→
   192→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, cfg.WebhookURL, bytes.NewReader(body))
   193→	if err != nil {
   194→		return fmt.Errorf("create request: %w", err)
   195→	}
   196→	req.Header.Set("Content-Type", "application/json")
   197→
   198→	client := s.Client
   199→	if client == nil {
   200→		client = http.DefaultClient
   201→	}
   202→
   203→	resp, err := client.Do(req)
   204→	if err != nil {
   205→		return fmt.Errorf("send slack notification: %w", err)
   206→	}
   207→	defer resp.Body.Close()
   208→
   209→	if resp.StatusCode >= 400 {
   210→		return fmt.Errorf("slack returned status %d", resp.StatusCode)
   211→	}
   212→	return nil
   213→}
