    91→func TestSlackSender_SemanticReport(t *testing.T) {
    92→	var received []byte
    93→	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    94→		received, _ = io.ReadAll(r.Body)
    95→		w.WriteHeader(http.StatusOK)
    96→	}))
    97→	defer srv.Close()
    98→
    99→	sender := &SlackSender{Client: srv.Client()}
   100→	ch := &models.NotificationChannel{
   101→		Type:   "slack",
   102→		Config: json.RawMessage(`{"webhook_url": "` + srv.URL + `"}`),
   103→	}
   104→
   105→	reportJSON := `{
   106→		"subject": "Ready to Deploy: go-ethereum v1.16.4",
   107→		"risk_level": "HIGH",
   108→		"risk_reason": "Version not found in sources",
   109→		"status_checks": ["Binaries Unverified", "Docker Image Unverified"],
   110→		"changelog_summary": "Security fixes and performance improvements",
   111→		"availability": "GA",
   112→		"adoption": "Recommended for production",
   113→		"urgency": "High",
   114→		"recommendation": "Deploy after verifying checksums",
   115→		"download_commands": ["docker pull ethereum/client-go:v1.16.4"],
   116→		"download_links": ["https://github.com/ethereum/go-ethereum/releases/tag/v1.16.4"]
   117→	}`
   118→
   119→	msg := Notification{
   120→		Title:   "Semantic Release Report: go-ethereum v1.16.4",
   121→		Body:    reportJSON,
   122→		Version: "v1.16.4",
   123→	}
   124→
   125→	err := sender.Send(context.Background(), ch, msg)
   126→	if err != nil {
   127→		t.Fatalf("unexpected error: %v", err)
   128→	}
   129→
   130→	var payload slackPayload
   131→	if err := json.Unmarshal(received, &payload); err != nil {
   132→		t.Fatalf("received invalid JSON: %v", err)
   133→	}
   134→
   135→	// Should have many more blocks than the simple 2-block fallback
   136→	if len(payload.Blocks) < 6 {
   137→		t.Fatalf("expected at least 6 blocks for semantic report, got %d", len(payload.Blocks))
   138→	}
   139→
   140→	// First block should be header
   141→	if payload.Blocks[0].Type != "header" {
   142→		t.Fatalf("expected first block to be header, got %s", payload.Blocks[0].Type)
   143→	}
   144→
   145→	// Second block should contain the subject
   146→	if payload.Blocks[1].Text == nil || !strings.Contains(payload.Blocks[1].Text.Text, "Ready to Deploy") {
   147→		t.Fatal("expected second block to contain the subject")
   148→	}
   149→
   150→	// Should have a section with fields (risk, urgency, availability)
   151→	hasFields := false
   152→	for _, b := range payload.Blocks {
   153→		if len(b.Fields) > 0 {
   154→			hasFields = true
   155→			// Check risk emoji is present
   156→			found := false
   157→			for _, f := range b.Fields {
   158→				if strings.Contains(f.Text, "🔴") && strings.Contains(f.Text, "HIGH") {
   159→					found = true
   160→				}
   161→			}
   162→			if !found {
   163→				t.Fatal("expected risk field with 🔴 HIGH emoji")
   164→			}
   165→		}
   166→	}
   167→	if !hasFields {
   168→		t.Fatal("expected at least one section with fields")
   169→	}
   170→
   171→	// Should have download commands in a code block
   172→	hasCode := false
   173→	for _, b := range payload.Blocks {
   174→		if b.Text != nil && strings.Contains(b.Text.Text, "```") && strings.Contains(b.Text.Text, "docker pull") {
   175→			hasCode = true
   176→		}
   177→	}
   178→	if !hasCode {
   179→		t.Fatal("expected download commands in a code block")
   180→	}
   181→
   182→	// Should have context footer
   183→	lastBlock := payload.Blocks[len(payload.Blocks)-1]
   184→	if lastBlock.Type != "context" {
   185→		t.Fatalf("expected last block to be context, got %s", lastBlock.Type)
   186→	}
   187→}
