/** Returns true if the string already contains HTML tags. */
function looksLikeHtml(s: string): boolean {
  return /<[a-z][\s\S]*>/i.test(s);
}

/** Convert changelog to HTML — pass through if already HTML, otherwise render as markdown. */
function changelogToHtml(raw: string): string {
  if (looksLikeHtml(raw)) return raw;
  return marked.parse(raw, { async: false }) as string;
}

function getProviderUrl(
  provider: string,
  repository: string,
  version: string
): string | null {
  switch (provider) {
    case "github":
      return `https://github.com/${repository}/releases/tag/${version}`;
    case "dockerhub":
      return `https://hub.docker.com/r/${repository}/tags?name=${encodeURIComponent(version)}`;
    case "ecr-public":
      return `https://gallery.ecr.aws/${repository}`;
    default:
      return null;
  }
}

function getProviderLabel(provider: string): string {
  switch (provider) {
    case "github":
      return "GitHub";
    case "dockerhub":
      return "Docker Hub";
    case "ecr-public":
      return "ECR Public";
    default:
      return provider;
  }
}

